import type { AuthenticationClient, DirectusClient, RestClient } from '@directus/sdk'
import type { ApiCollections } from '~/types/schema'
import { authentication, createDirectus, login as directusLogin, readMe, rest } from '@directus/sdk'

/**
 * AuthService encapsula autenticação e gerenciamento do usuário autenticado via Directus.
 * Evita múltiplos fetchs da URL do Directus e expõe métodos para login, logout, token e avatar.
 */
class AuthService {
  private directusUrl: string | null = null
  private token: string | null = null
  private _refreshToken: string | null = null
  public loading = ref(false)
  public error = ref<Error | null>(null)
  public isAuthenticated = ref(false)
  public user = ref<any>(null)

  constructor() {
    // Restaura o token do localStorage, se existir
    if (typeof window !== 'undefined') {
      const storedToken = localStorage.getItem('directus_token')
      if (storedToken) {
        this.token = storedToken
      }
      const storedRefreshToken = localStorage.getItem('directus_refresh_token')
      if (storedRefreshToken) {
        this._refreshToken = storedRefreshToken
      }
    }
  }

  /**
   * Busca e armazena a URL do Directus apenas uma vez.
   */
  ensureDirectusUrl = async (): Promise<string> => {
    if (!this.directusUrl) {
      const { url } = await $fetch<{ url: string }>('/api/directus')
      this.directusUrl = url
    }
    return this.directusUrl
  }

  /**
   * Cria um cliente Directus com autenticação por token estático
   * @param token Token estático para autenticação
   */
  public async getStaticClient(token?: string): Promise<DirectusClient<ApiCollections> & RestClient<ApiCollections> & AuthenticationClient<ApiCollections>> {
    const url = await this.ensureDirectusUrl()
    const client = createDirectus<ApiCollections>(url)
      .with(rest())
      .with(authentication())
    if (token) {
      client.setToken(token)
    }
    return client
  }

  /**
   * Cria um cliente Directus com autenticação por login/senha
   */
  /**
   * Cria um cliente Directus com autenticação por login/senha (modo JSON, recomendado para login via API)
   */
  public async getAuthClient(): Promise<DirectusClient<ApiCollections> & RestClient<ApiCollections> & AuthenticationClient<ApiCollections>> {
    const url = await this.ensureDirectusUrl()
    const client = createDirectus<ApiCollections>(url)
      .with(rest())
      .with(authentication('json'))
    if (this.token) {
      client.setToken(this.token)
    }
    return client
  }

  /**
   * Realiza login com email e senha
   * @param credentials Credenciais de login
   */
  /**
   * Realiza login com email e senha usando o authentication('json')
   * @param credentials Credenciais de login
   */
  public async entrar(credentials: { email: string, password: string }) {
    this.loading.value = true
    this.error.value = null
    try {
      const client = await this.getAuthClient()
      // Alternativa: login via request(login(...)) para máxima compatibilidade
      const result = await client.request(directusLogin({ email: credentials.email, password: credentials.password }))
      if (result.access_token) {
        this.token = result.access_token
        if (result.refresh_token) {
          this._refreshToken = result.refresh_token
        }
        if (typeof window !== 'undefined') {
          localStorage.setItem('directus_token', this.token)
          if (this._refreshToken) {
            localStorage.setItem('directus_refresh_token', this._refreshToken)
          }
        }
        this.isAuthenticated.value = true
        await this.fetchCurrentUser()
      }
      return result
    }
    catch (e) {
      this.error.value = e as Error
      this.isAuthenticated.value = false
      this.user.value = null
      this.token = null
      console.error('Login failed:', e)
      throw e
    }
    finally {
      this.loading.value = false
    }
  }

  /**
   * Verifica se o usuário atual está autenticado e busca seus dados
   * @returns Os dados do usuário se autenticado, caso contrário, `null`
   */
  public async checkUser() {
    try {
      const client = await this.getAuthClient()
      const userData = await client.request(readMe({
        fields: ['id', 'email', 'first_name', 'last_name', 'role', 'avatar'],
      }))
      if (userData) {
        this.isAuthenticated.value = true
        this.user.value = userData
        return userData
      }
      return null
    }
    catch {
      this.isAuthenticated.value = false
      this.user.value = null
      return null
    }
  }

  /**
   * Busca os dados do usuário atual
   */
  public async fetchCurrentUser() {
    try {
      const client = await this.getAuthClient()
      const userData = await client.request(readMe())
      this.user.value = userData
      return userData
    }
    catch (e) {
      console.error('Falha ao buscar dados do usuário:', e)
      this.user.value = null
      return null
    }
  }

  /**
   * Obtém o token de acesso do usuário autenticado
   * @returns O token de acesso ou `null` se ocorrer um erro
   */
  public async getToken() {
    try {
      const client = await this.getAuthClient()
      return await client.getToken()
    }
    catch (e) {
      console.error('Falha ao obter o token:', e)
      return null
    }
  }

  /**
   * Realiza o logout do usuário, invalidando o token
   */
  public async logout() {
    this.loading.value = true
    try {
      // Realiza o logout localmente, sem depender do refresh token
      this.isAuthenticated.value = false
      this.user.value = null
      this.error.value = null
      this.token = null
      this._refreshToken = null
      if (typeof window !== 'undefined') {
        localStorage.removeItem('directus_token')
        localStorage.removeItem('directus_refresh_token')
      }
      // Limpa o cache do usuário se o composable useUser existir (evita erro SSR)
      try {
        if (typeof window !== 'undefined' && typeof (window as any).useUser === 'function') {
          const { clearUser } = (window as any).useUser()
          if (typeof clearUser === 'function')
            clearUser()
        }
      }
      catch {
        // useUser pode não existir
      }
      // Redireciona para a página de login
      await navigateTo('/admin')
    }
    catch (e) {
      console.error('Falha ao fazer logout:', e)
      this.error.value = e as Error
    }
    finally {
      this.loading.value = false
    }
  }

  /**
   * Refresh do token de autenticação
   */
  public async refreshToken() {
    try {
      const client = await this.getAuthClient()
      const result = await client.refresh()
      if (result.access_token) {
        this.token = result.access_token
        if (result.refresh_token) {
          this._refreshToken = result.refresh_token
        }
        if (typeof window !== 'undefined') {
          localStorage.setItem('directus_token', this.token)
          if (this._refreshToken) {
            localStorage.setItem('directus_refresh_token', this._refreshToken)
          }
        }
        this.isAuthenticated.value = true
        await this.fetchCurrentUser()
      }
      return result
    }
    catch (e) {
      console.error('Falha ao renovar token:', e)
      this.isAuthenticated.value = false
      this.user.value = null
      this.token = null
      this.error.value = e as Error
      return null
    }
  }

  /**
   * Gera a URL do avatar do usuário autenticado, se disponível.
   * @returns string | null
   */
  public getUserAvatarUrl(): string | null {
    if (!this.user.value || !this.user.value.avatar)
      return null
    if (!this.directusUrl)
      return null
    let url = `${this.directusUrl.replace(/\/$/, '')}/assets/${this.user.value.avatar}`
    if (this.token) {
      url += `?access_token=${this.token}`
    }
    return url
  }

  public async init() {
    return this.checkUser()
  }
}

let _authService: AuthService | null = null

/**
 * useAuth composable: retorna singleton do AuthService e proxies para reatividade.
 */
export function useAuth() {
  if (!_authService) {
    _authService = new AuthService()
    // Executa verificação inicial de autenticação
    if (typeof window !== 'undefined') {
      _authService.init()
    }
  }
  return {
    // Clients
    getStaticClient: _authService.getStaticClient.bind(_authService),
    getAuthClient: _authService.getAuthClient.bind(_authService),

    // Authentication methods
    entrar: _authService.entrar.bind(_authService),
    logout: _authService.logout.bind(_authService),
    refreshToken: _authService.refreshToken.bind(_authService), // método público, não a propriedade

    // User methods
    checkUser: _authService.checkUser.bind(_authService),
    fetchCurrentUser: _authService.fetchCurrentUser.bind(_authService),
    getToken: _authService.getToken.bind(_authService),
    getUserAvatarUrl: _authService.getUserAvatarUrl.bind(_authService),

    // State
    loading: _authService.loading,
    error: _authService.error,
    isAuthenticated: _authService.isAuthenticated,
    user: _authService.user,
  }
}

import 'dotenv/config'

async function run() {
  const url = process.env.NUXT_PUBLIC_DIRECTUS_URL
  const token = process.env.DIRECTUS_TOKEN

  try {
    const res = await fetch(`${url}/collections`, {
      headers: { Authorization: `Bearer ${token}` },
    })

    if (res.ok) {
      const json = await res.json()
      const pdvCols = json.data.filter((c: any) => c.collection.startsWith('pdv_'))
      console.log('PDV Collections:', pdvCols.map((c: any) => c.collection))
    }
    else {
      const txt = await res.text()
      console.log('Error fetching collections:', res.status, txt)
    }
  }
  catch (error) {
    console.error('Fetch error:', error)
  }
}

run()

import { createCollection, createDirectus, createField, createRelation, rest, staticToken } from '@directus/sdk'
import 'dotenv/config'

// Make sure you have dotenv installed or the env vars are available
const url = process.env.NUXT_PUBLIC_DIRECTUS_URL || 'http://localhost:8055'
const token = process.env.DIRECTUS_TOKEN

if (!token) {
  console.error('DIRECTUS_TOKEN is missing in environment variables.')
  process.exit(1)
}

const client = createDirectus(url).with(staticToken(token)).with(rest())

async function run() {
  try {
    console.log('Creating pdv_categories...')
    await client.request(createCollection({
      collection: 'pdv_categories',
      schema: {},
      meta: {
        icon: 'category',
        note: 'Categorias de produtos do PDV',
        translations: [{ language: 'pt-BR', translation: 'Categorias PDV' }],
      },
    }))
    await client.request(createField('pdv_categories', {
      field: 'status',
      type: 'string',
      meta: { interface: 'select-dropdown', choices: [{ text: 'Rascunho', value: 'draft' }, { text: 'Publicado', value: 'published' }, { text: 'Arquivado', value: 'archived' }] },
    }))
    await client.request(createField('pdv_categories', { field: 'nome', type: 'string', schema: { is_nullable: false } }))
    await client.request(createField('pdv_categories', { field: 'descricao', type: 'text' }))
    await client.request(createField('pdv_categories', { field: 'icone', type: 'string' }))

    console.log('Creating pdv_products...')
    await client.request(createCollection({
      collection: 'pdv_products',
      schema: {},
      meta: {
        icon: 'inventory_2',
        note: 'Produtos do PDV',
        translations: [{ language: 'pt-BR', translation: 'Produtos PDV' }],
      },
    }))
    await client.request(createField('pdv_products', { field: 'status', type: 'string', meta: { interface: 'select-dropdown', choices: [{ text: 'Rascunho', value: 'draft' }, { text: 'Publicado', value: 'published' }, { text: 'Arquivado', value: 'archived' }] } }))
    await client.request(createField('pdv_products', { field: 'nome', type: 'string', schema: { is_nullable: false } }))
    await client.request(createField('pdv_products', { field: 'descricao', type: 'text' }))
    await client.request(createField('pdv_products', { field: 'preco', type: 'decimal', schema: { is_nullable: false } }))
    await client.request(createField('pdv_products', { field: 'custo', type: 'decimal' }))
    await client.request(createField('pdv_products', { field: 'estoque_atual', type: 'integer', schema: { default_value: 0 } }))
    await client.request(createField('pdv_products', { field: 'estoque_minimo', type: 'integer', schema: { default_value: 0 } }))
    await client.request(createField('pdv_products', { field: 'unidade', type: 'string', meta: { interface: 'select-dropdown', choices: [{ text: 'Unidade', value: 'un' }, { text: 'Quilo', value: 'kg' }, { text: 'Litro', value: 'lt' }] } }))
    // relations
    await client.request(createField('pdv_products', { field: 'categoria', type: 'uuid' }))
    await client.request(createRelation({
      collection: 'pdv_products',
      field: 'categoria',
      related_collection: 'pdv_categories',
    }))
    await client.request(createField('pdv_products', { field: 'imagem', type: 'uuid' }))
    await client.request(createRelation({
      collection: 'pdv_products',
      field: 'imagem',
      related_collection: 'directus_files',
    }))

    console.log('Creating pdv_stock_movements...')
    await client.request(createCollection({
      collection: 'pdv_stock_movements',
      schema: {},
      meta: { icon: 'swap_horiz', translations: [{ language: 'pt-BR', translation: 'Movimentações de Estoque PDV' }] },
    }))
    await client.request(createField('pdv_stock_movements', { field: 'tipo', type: 'string', meta: { interface: 'select-dropdown', choices: [{ text: 'Entrada', value: 'entrada' }, { text: 'Saída', value: 'saida' }, { text: 'Ajuste', value: 'ajuste' }] } }))
    await client.request(createField('pdv_stock_movements', { field: 'quantidade', type: 'integer', schema: { is_nullable: false } }))
    await client.request(createField('pdv_stock_movements', { field: 'motivo', type: 'string' }))
    await client.request(createField('pdv_stock_movements', { field: 'date_created', type: 'timestamp', meta: { special: ['date-created'] } }))
    await client.request(createField('pdv_stock_movements', { field: 'user_created', type: 'uuid', meta: { special: ['user-created'] } }))
    // relations
    await client.request(createField('pdv_stock_movements', { field: 'produto', type: 'uuid' }))
    await client.request(createRelation({ collection: 'pdv_stock_movements', field: 'produto', related_collection: 'pdv_products' }))
    await client.request(createRelation({ collection: 'pdv_stock_movements', field: 'user_created', related_collection: 'directus_users' }))

    console.log('Creating pdv_sales...')
    await client.request(createCollection({
      collection: 'pdv_sales',
      schema: {},
      meta: { icon: 'point_of_sale', translations: [{ language: 'pt-BR', translation: 'Vendas PDV' }] },
    }))
    await client.request(createField('pdv_sales', { field: 'status', type: 'string', meta: { interface: 'select-dropdown', choices: [{ text: 'Aberta', value: 'aberta' }, { text: 'Finalizada', value: 'finalizada' }, { text: 'Cancelada', value: 'cancelada' }] } }))
    await client.request(createField('pdv_sales', { field: 'total', type: 'decimal' }))
    await client.request(createField('pdv_sales', { field: 'forma_pagamento', type: 'string', meta: { interface: 'select-dropdown', choices: [{ text: 'Dinheiro', value: 'dinheiro' }, { text: 'PIX', value: 'pix' }, { text: 'Cartão', value: 'cartao' }] } }))
    await client.request(createField('pdv_sales', { field: 'observacao', type: 'text' }))
    await client.request(createField('pdv_sales', { field: 'date_created', type: 'timestamp', meta: { special: ['date-created'] } }))
    await client.request(createField('pdv_sales', { field: 'user_created', type: 'uuid', meta: { special: ['user-created'] } }))
    await client.request(createRelation({ collection: 'pdv_sales', field: 'user_created', related_collection: 'directus_users' }))

    console.log('Creating pdv_sale_items...')
    await client.request(createCollection({
      collection: 'pdv_sale_items',
      schema: {},
      meta: { icon: 'receipt_long', translations: [{ language: 'pt-BR', translation: 'Itens de Venda PDV' }] },
    }))
    await client.request(createField('pdv_sale_items', { field: 'quantidade', type: 'integer', schema: { is_nullable: false } }))
    await client.request(createField('pdv_sale_items', { field: 'preco_unitario', type: 'decimal', schema: { is_nullable: false } }))
    await client.request(createField('pdv_sale_items', { field: 'subtotal', type: 'decimal', schema: { is_nullable: false } }))
    // relations
    await client.request(createField('pdv_sale_items', { field: 'venda', type: 'uuid' }))
    await client.request(createRelation({ collection: 'pdv_sale_items', field: 'venda', related_collection: 'pdv_sales' }))
    await client.request(createField('pdv_sale_items', { field: 'produto', type: 'uuid' }))
    await client.request(createRelation({ collection: 'pdv_sale_items', field: 'produto', related_collection: 'pdv_products' }))

    console.log('All collections created successfully!')
  }
  catch (error) {
    console.error('Error creating collections:', error)
  }
}

run()

import { authentication, createDirectus, readCollections, readItems, rest } from '@directus/sdk'

async function testFetch() {
  const url = process.env.NUXT_PUBLIC_DIRECTUS_URL || 'https://capela.softagon.app'
  console.log('Using URL:', url)

  const client = createDirectus(url).with(authentication()).with(rest())

  try {
    const auth = await client.login('hermes@softagon.com.br', 'Softagon@2025')
    console.log('Login successful!', auth.access_token ? 'Got token' : 'No token')

    // First try to load collections
    console.log('\n--- Checking collections ---')
    try {
      const collections = await client.request(readCollections())
      const pdvCols = collections.filter(c => c.collection.startsWith('pdv_')).map(c => c.collection)
      console.log('PDV Collections:', pdvCols)
    }
    catch (e: any) {
      console.error('Error reading collections:', e.errors || e.message)
    }

    // Try to load a specific PDV table to see if it's there
    console.log('\n--- Checking pdv_categories ---')
    try {
      const cats = await client.request(readItems('pdv_categories', { limit: 1 }))
      console.log('Fetched categories:', cats)
    }
    catch (e: any) {
      console.error('Error fetching categories:', e.errors || e.message)
    }

    // Checking pdv_products
    console.log('\n--- Checking pdv_products ---')
    try {
      const prods = await client.request(readItems('pdv_products', { limit: 1 }))
      console.log('Fetched products:', prods)
    }
    catch (e: any) {
      console.error('Error fetching products:', e.errors || e.message)
    }
  }
  catch (error: any) {
    console.error('Login or General Error:', error.errors || error.message)
  }
}

testFetch()
